import { Component, OnInit, AfterViewInit, ElementRef, ViewChild } from '@angular/core';
import { Chart, registerables } from 'chart.js';
import { CommonModule } from '@angular/common'; // استيراد أساسي
Chart.register(...registerables);

interface Appointment {
  id: number;
  name: string;
  date: string;
  status: 'Pending' | 'Accepted' | 'Rejected';
  showDropdown?: boolean;
}

interface Doctor {
  id: string;
  name: string;
  mobile: string;
  address: string;
  charge: string;
  education: string;
  dob: string;
  status: 'Active' | 'Offline';
}

@Component({
  selector: 'app-admin-dashboard',
  imports: [CommonModule], // تأكدي من وجودها هنا لكي يعمل الـ ngClass والـ ngFor
  templateUrl: './admin-dashboard.component.html',
  styleUrls: ['./admin-dashboard.component.scss']
})
export class AdminDashboardComponent implements OnInit, AfterViewInit {
  @ViewChild('patientsChart') patientsChartCanvas!: ElementRef<HTMLCanvasElement>;

  sidebarCollapsed = false;

  // Stats Counters
  totalPatients = 39;
  totalDoctors = 29;
  totalWards = 30;
  totalLabs = 29;

  // Appointment Queue State
  appointments: Appointment[] = [
    { id: 1, name: 'Ahamed Shraaz', date: '15.10.2025 - 12:30', status: 'Pending' },
    { id: 2, name: 'Daphne Kanon', date: '14.10.2025 - 08:15', status: 'Rejected' },
    { id: 3, name: 'Prabash Lakshitha', date: '18.10.2025 - 10:45', status: 'Pending' },
    { id: 4, name: 'Malith De Silva', date: '14.10.2025 - 15:20', status: 'Pending' },
    { id: 5, name: 'Imran Al-Habeeb', date: '15.10.2025 - 09:50', status: 'Accepted' }
  ];

  // Doctors State
  doctors: Doctor[] = [
    { id: 'D-092', name: 'Dr. John Smith', mobile: '0124892482', address: 'Assiut, Egypt', charge: '$150.00', education: 'MBBS, MD', dob: '12-05-1988', status: 'Active' },
    { id: 'D-041', name: 'Dr. Sarah Connor', mobile: '0104829421', address: 'New Cairo, Egypt', charge: '$200.00', education: 'MBBS, PhD', dob: '24-08-1991', status: 'Active' },
    { id: 'D-112', name: 'Dr. Michael Scott', mobile: '0112489344', address: 'Maadi, Egypt', charge: '$100.00', education: 'DNB, Medicine', dob: '05-11-1985', status: 'Offline' }
  ];

  ngOnInit(): void {}

  ngAfterViewInit(): void {
    this.initPatientsChart();
  }

  toggleSidebar() {
    this.sidebarCollapsed = !this.sidebarCollapsed;
  }

  toggleDropdown(app: Appointment, event: Event) {
    event.stopPropagation();
    // Close other dropdowns
    this.appointments.forEach(a => {
      if (a.id !== app.id) a.showDropdown = false;
    });
    app.showDropdown = !app.showDropdown;
  }

  updateAppointmentStatus(app: Appointment, status: 'Accepted' | 'Rejected') {
    app.status = status;
    app.showDropdown = false;
  }

  removeDoctor(docId: string) {
    if (confirm(`Are you sure you want to remove Doctor ${docId}?`)) {
      this.doctors = this.doctors.filter(d => d.id !== docId);
      this.totalDoctors = this.doctors.length + 27; // updating global statistical counts dynamically
    }
  }

  private initPatientsChart() {
    const ctx = this.patientsChartCanvas.nativeElement.getContext('2d');
    if (!ctx) return;

    const purpleGradient = ctx.createLinearGradient(0, 0, 0, 250);
    purpleGradient.addColorStop(0, 'rgba(146, 121, 195, 0.45)');
    purpleGradient.addColorStop(1, 'rgba(146, 121, 195, 0.01)');

    new Chart(ctx, {
      type: 'line',
      data: {
        labels: ['Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat', 'Sun'],
        datasets: [{
          data: [65, 80, 52, 95, 85, 60, 75],
          borderColor: '#9279c3',
          borderWidth: 3,
          pointBackgroundColor: '#FFFFFF',
          pointBorderColor: '#795eb0',
          pointBorderWidth: 2,
          pointRadius: 5,
          tension: 0.45,
          fill: true,
          backgroundColor: purpleGradient
        }]
      },
      options: {
        responsive: true,
        maintainAspectRatio: false,
        plugins: { legend: { display: false } },
        scales: {
          x: { grid: { display: false } },
          y: { grid: { color: '#f1f5f9' } }
        }
      }
    });
  }
}
